import{_ as t,o as r,c as a,ag as s}from"./chunks/framework.Culc7SYV.js";const h=JSON.parse('{"title":"Suspending Cards","description":"","frontmatter":{},"headers":[],"relativePath":"Suspending-Cards.md","filePath":"Suspending-Cards.md","lastUpdated":1772690052000}'),o={name:"Suspending-Cards.md"};function n(d,e,i,u,l,p){return r(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="suspending-cards" tabindex="-1">Suspending Cards <a class="header-anchor" href="#suspending-cards" aria-label="Permalink to &quot;Suspending Cards&quot;">​</a></h1><p>Last modified: 17/03/2026</p><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>Suspending removes a card from study sessions until you unsuspend it.</p><p>The card is kept in your collection, but it is not shown for review.</p><p>Unlike burying, suspension does not reset automatically.</p><h2 id="suspend-steps" tabindex="-1">Suspend Steps <a class="header-anchor" href="#suspend-steps" aria-label="Permalink to &quot;Suspend Steps&quot;">​</a></h2><h3 id="during-a-study-session" tabindex="-1">During a study session <a class="header-anchor" href="#during-a-study-session" aria-label="Permalink to &quot;During a study session&quot;">​</a></h3><ul><li>Press <strong><code>S</code></strong> on your keyboard, or</li><li>Open the <strong>More menu</strong> (press <code>M</code> or tap <strong>⋮</strong>) and choose <strong>Suspend</strong>.</li></ul><h3 id="from-the-card-browser" tabindex="-1">From the Card Browser <a class="header-anchor" href="#from-the-card-browser" aria-label="Permalink to &quot;From the Card Browser&quot;">​</a></h3><ol><li>Open the <a href="./Card-Browser">Card Browser</a>.</li><li>Select one or more cards.</li><li>Click the <strong>Suspend</strong> button in the bulk actions bar.</li></ol><p>To unsuspend, select suspended cards and click <strong>Unsuspend</strong>.</p><h2 id="find-suspended" tabindex="-1">Find Suspended <a class="header-anchor" href="#find-suspended" aria-label="Permalink to &quot;Find Suspended&quot;">​</a></h2><p>In <a href="./Card-Browser">Card Browser</a>, filter by Stage -&gt; Suspended.</p><h2 id="use-cases" tabindex="-1">Use Cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to &quot;Use Cases&quot;">​</a></h2><p>Suspending is useful when:</p><ul><li>A card is outdated or incorrect and you want to stop reviewing it until you fix the content.</li><li>You&#39;re studying a subset of material (e.g. only certain chapters) and want to temporarily exclude other cards.</li><li>A card is a leech (you keep forgetting it) and you need to rewrite it before continuing.</li></ul><h2 id="compare-bury" tabindex="-1">Compare Bury <a class="header-anchor" href="#compare-bury" aria-label="Permalink to &quot;Compare Bury&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>Bury</th><th>Suspend</th></tr></thead><tbody><tr><td><strong>Duration</strong></td><td>Until midnight (automatic reset)</td><td>Until you manually unsuspend</td></tr><tr><td><strong>Best for</strong></td><td>Skipping a card for the rest of the day</td><td>Removing a card from reviews long-term</td></tr><tr><td><strong>Scheduling impact</strong></td><td>None</td><td>None</td></tr><tr><td><strong>How to reverse</strong></td><td>Automatic (next day)</td><td>Manual (unsuspend in browser or during study)</td></tr></tbody></table><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>Use <strong>Bury</strong> for &quot;I&#39;ll try again tomorrow&quot; and <strong>Suspend</strong> for &quot;I need to fix this card first.&quot;</p></div><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./Burying-Cards">Burying Cards</a></li><li><a href="./Card-Browser">Card Browser</a></li></ul>',22)])])}const g=t(o,[["render",n]]);export{h as __pageData,g as default};
